    24→    eventServerResponse('ORDER_DETAIL_SUCCESS' as never);
    25→  } else {
    26→    handleOrderDetailError();
    27→  }
    28→}
    29→
    30→function handleOrderDetailError(): void {
    31→  const { orderDetailActions } = useRootStore.getState();
    32→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.ERROR);
    33→  eventServerResponse('ORDER_DETAIL_ERROR' as never);
    34→}
    35→
    36→export async function getOrderDetail(
    37→  payload: GetOrderDetailPayload,
    38→): Promise<void> {
    39→  const { orderDetailActions, orderDetail } = useRootStore.getState();
    40→
    41→  const isDifferentTransaction =
    42→    orderDetail.transactionId !== payload.transactionId;
    43→  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;
    44→
    45→  if (isAlreadyLoading && !isDifferentTransaction) {
    46→    return;
    47→  }
    48→
    49→  if (isDifferentTransaction) {
    50→    orderDetailActions.reset();
    51→  }
    52→
    53→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.LOADING);
    54→
    55→  try {
    56→    const participantId =
    57→      payload?.participantId ?? (await getParticipantIdFromToken());
    58→
    59→    if (!participantId) {
    60→      handleOrderDetailError();
    61→      return;
    62→    }
    63→
    64→    const requestPayload: OrderDetailRequestDto = {
    65→      transactionId: payload.transactionId,
    66→      participantId,
    67→    };
    68→
    69→    const response = await getOrderDetailApi(requestPayload);
    70→    const orderDetailData = getOrderDetailFromResponse(response);
    71→
    72→    if (orderDetailData) {
    73→      handleOrderDetailSuccess(orderDetailData, payload.transactionId);
    74→      return;
    75→    }
    76→
    77→    handleOrderDetailError();
    78→  } catch {
    79→    handleOrderDetailError();
    80→  }
    81→}
    82→

